import{_ as s,c as a,o as i,ae as t}from"./chunks/framework.BHrE6nLq.js";const m=JSON.parse('{"title":"Encrypting QCOW2 Custom Images","description":"","frontmatter":{},"headers":[],"relativePath":"how_to/libvirt/encrypt-images.md","filePath":"how_to/libvirt/encrypt-images.md"}'),n={name:"how_to/libvirt/encrypt-images.md"};function p(o,e,c,r,l,h){return i(),a("div",null,e[0]||(e[0]=[t(`<h1 id="encrypting-qcow2-custom-images" tabindex="-1">Encrypting QCOW2 Custom Images <a class="header-anchor" href="#encrypting-qcow2-custom-images" aria-label="Permalink to &quot;Encrypting QCOW2 Custom Images&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Encrypting virtual machine (VM) disk images, such as those in the QCOW2 format, adds a layer of security by protecting their contents with a password. This is particularly useful for sensitive data in environments like Qemu/KVM. In this guide, we’ll walk through the process of creating an encrypted QCOW2 image and converting an existing unencrypted image to an encrypted one using the <code>qemu-img</code> tool on a Linux system.</p><h2 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-label="Permalink to &quot;Environment&quot;">​</a></h2><ul><li><strong>Qemu/KVM</strong>: A virtualization platform for managing VMs.</li><li><strong>Operating System</strong>: Linux (commands are tested on Linux distributions like Ubuntu, CentOS, or Rocky Linux).</li><li><strong>Tools</strong>: <code>qemu-img</code> (part of <code>qemu-utils</code> or <code>qemu-kvm</code> packages).</li></ul><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><h3 id="step-1-prepare-the-image" tabindex="-1">Step 1 - Prepare the Image <a class="header-anchor" href="#step-1-prepare-the-image" aria-label="Permalink to &quot;Step 1 - Prepare the Image&quot;">​</a></h3><p>Start by identifying or preparing the QCOW2 image you want to encrypt. For this guide, we’ll assume you have an existing unencrypted image (e.g., <code>my_100G_custom_image.qcow2</code>) or will create a new one. Ensure <code>qemu-img</code> is installed:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-utils</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # For Debian/Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-img</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # For RHEL/CentOS/Rocky</span></span></code></pre></div><h3 id="step-2-check-image-information" tabindex="-1">Step 2 - Check Image Information <a class="header-anchor" href="#step-2-check-image-information" aria-label="Permalink to &quot;Step 2 - Check Image Information&quot;">​</a></h3><p>Before proceeding, inspect the details of your existing QCOW2 image to confirm its format and properties. Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_100G_custom_image.qcow2</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>image: my_100G_custom_image.qcow2</span></span>
<span class="line"><span>file format: qcow2</span></span>
<span class="line"><span>virtual size: 100 GiB (107374182400 bytes)</span></span>
<span class="line"><span>disk size: 1.2 GiB</span></span>
<span class="line"><span>cluster_size: 65536</span></span>
<span class="line"><span>Format specific information:</span></span>
<span class="line"><span>    compat: 1.1</span></span>
<span class="line"><span>    compression type: zlib</span></span>
<span class="line"><span>    lazy refcounts: false</span></span>
<span class="line"><span>    refcount bits: 16</span></span>
<span class="line"><span>    corrupt: false</span></span></code></pre></div><p>This confirms the image is in QCOW2 format and not yet encrypted.</p><h3 id="step-3-create-an-encrypted-qcow2-image" tabindex="-1">Step 3 - Create an Encrypted QCOW2 Image <a class="header-anchor" href="#step-3-create-an-encrypted-qcow2-image" aria-label="Permalink to &quot;Step 3 - Create an Encrypted QCOW2 Image&quot;">​</a></h3><p>Create a new encrypted QCOW2 image with a password. In this example, we’ll use the password <code>tes123</code> and set the size to 10GB (you can adjust the size as needed). Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=tes123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> encrypt.format=luks,encrypt.key-secret=sec0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_10G_custom_image-encrypted.qcow2</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 10G</span></span></code></pre></div><p>Here’s what the command does:</p><ul><li><code>--object secret,id=sec0,data=tes123</code>: Defines a secret (password) with ID <code>sec0</code> and value <code>tes123</code>.</li><li><code>-f qcow2</code>: Specifies the QCOW2 format.</li><li><code>-o encrypt.format=luks,encrypt.key-secret=sec0</code>: Enables LUKS encryption using the defined secret.</li><li><code>my_10G_custom_image-encrypted.qcow2</code>: The output file name.</li><li><code>10G</code>: The virtual size of the image (10 gigabytes).</li></ul><p>After running this, you’ll have a new, empty, encrypted QCOW2 image.</p><h3 id="step-4-convert-an-existing-image-to-encrypted-format" tabindex="-1">Step 4 - Convert an Existing Image to Encrypted Format <a class="header-anchor" href="#step-4-convert-an-existing-image-to-encrypted-format" aria-label="Permalink to &quot;Step 4 - Convert an Existing Image to Encrypted Format&quot;">​</a></h3><p>If you have an unencrypted image (e.g., <code>my_100G_custom_image.qcow2</code>) and want to encrypt it, use the <code>qemu-img convert</code> command. This copies the contents of the unencrypted image into the encrypted one created in Step 3. Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> convert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=tes123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,file.filename=my_100G_custom_image.qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --target-image-opts</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> driver=qcow2,encrypt.key-secret=sec0,file.filename=my_10G_custom_image-encrypted.qcow2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p>Breaking it down:</p><ul><li><code>--object secret,id=sec0,data=tes123</code>: Specifies the password (<code>tes123</code>) for encryption.</li><li><code>--image-opts driver=qcow2,file.filename=my_100G_custom_image.qcow2</code>: Defines the source image.</li><li><code>--target-image-opts driver=qcow2,encrypt.key-secret=sec0,file.filename=my_10G_custom_image-encrypted.qcow2</code>: Specifies the encrypted target image.</li><li><code>-n</code>: Skips pre-allocating the target (faster but may fragment the file).</li><li><code>-p</code>: Displays a progress bar during conversion.</li></ul><p>Wait for the process to complete. The duration depends on the size of the source image.</p><h3 id="step-5-verify-encryption" tabindex="-1">Step 5 - Verify Encryption <a class="header-anchor" href="#step-5-verify-encryption" aria-label="Permalink to &quot;Step 5 - Verify Encryption&quot;">​</a></h3><p>Check the new encrypted image to confirm it’s properly encrypted. Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qemu-img</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my_10G_custom_image-encrypted.qcow2</span></span></code></pre></div><p>Example output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>image: my_10G_custom_image-encrypted.qcow2</span></span>
<span class="line"><span>file format: qcow2</span></span>
<span class="line"><span>virtual size: 10 GiB (10737418240 bytes)</span></span>
<span class="line"><span>disk size: 1.5 GiB</span></span>
<span class="line"><span>cluster_size: 65536</span></span>
<span class="line"><span>Format specific information:</span></span>
<span class="line"><span>    compat: 1.1</span></span>
<span class="line"><span>    compression type: zlib</span></span>
<span class="line"><span>    lazy refcounts: false</span></span>
<span class="line"><span>    refcount bits: 16</span></span>
<span class="line"><span>    encrypt:</span></span>
<span class="line"><span>        format: luks</span></span>
<span class="line"><span>        cipher-alg: aes-256</span></span>
<span class="line"><span>        cipher-mode: xts</span></span>
<span class="line"><span>        ivgen-alg: plain64</span></span>
<span class="line"><span>    corrupt: false</span></span></code></pre></div><p>Look for the <code>encrypt</code> section in the output—this confirms the image is encrypted with LUKS.</p><h2 id="using-the-encrypted-image" tabindex="-1">Using the Encrypted Image <a class="header-anchor" href="#using-the-encrypted-image" aria-label="Permalink to &quot;Using the Encrypted Image&quot;">​</a></h2><p>To use this image in Qemu/KVM, you’ll need to provide the password when launching the VM. For example, with <code>virt-install</code> or a Qemu command line, include the secret object:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-object</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secret,id=sec0,data=tes123</span></span></code></pre></div><p>Add this to your VM configuration or startup command, along with the path to the encrypted image.</p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://cloud.ibm.com/docs/vpc?topic=vpc-create-encrypted-custom-image" target="_blank" rel="noreferrer">IBM Cloud: Creating an Encrypted Custom Image</a></li></ul>`,39)]))}const g=s(n,[["render",p]]);export{m as __pageData,g as default};
